package com.example.config;

import org.springframework.boot.autoconfigure.condition.ConditionalOnClass;
import org.springframework.boot.autoconfigure.condition.ConditionalOnMissingBean;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
@ConditionalOnClass(CacheService.class)
@ConditionalOnProperty(prefix = "app.cache", name = "enabled", havingValue = "true")
public class CustomAutoConfiguration {

    @Bean
    @ConditionalOnMissingBean(CacheService.class)
    public CacheService cacheService(CacheProperties properties) {
        if (properties.getType().equals("redis")) {
            return new RedisCacheService(properties.getRedis());
        } else if (properties.getType().equals("caffeine")) {
            return new CaffeineCacheService(properties.getCaffeine());
        }
        throw new IllegalArgumentException("Unsupported cache type: " + properties.getType());
    }

    @Bean
    @ConditionalOnMissingBean(CacheSerializer.class)
    public CacheSerializer cacheSerializer() {
        return new JsonSerializer();
    }

    @Bean
    @ConditionalOnClass(name = "com.fasterxml.jackson.databind.ObjectMapper")
    public JacksonCacheSerializer jacksonCacheSerializer() {
        return new JacksonCacheSerializer();
    }
}

@ConfigurationProperties(prefix = "app.cache")
public class CacheProperties {
    private boolean enabled = true;
    private String type = "caffeine";
    private RedisProperties redis = new RedisProperties();
    private CaffeineProperties caffeine = new CaffeineProperties();

    // getters and setters
}

public interface CacheService {
    <T> T get(String key, Class<T> type);
    void put(String key, Object value, long ttlSeconds);
    void evict(String key);
}

package com.example.cqrs;

import java.time.Instant;
import java.util.ArrayList;
import java.util.List;

public class OrderAggregate {
    private String orderId;
    private String customerId;
    private List<OrderEvent> events = new ArrayList<>();
    private OrderState state = new OrderState();

    public OrderAggregate(String orderId, String customerId) {
        this.orderId = orderId;
        this.customerId = customerId;
        applyEvent(new OrderCreated(orderId, customerId, Instant.now()));
    }

    public void addItem(String productId, String productName, int quantity, double price) {
        if (!state.isActive()) {
            throw new IllegalStateException("Order is not active");
        }
        applyEvent(new ItemAdded(orderId, productId, productName, quantity, price, Instant.now()));
    }

    public void submit() {
        if (state.getItems().isEmpty()) {
            throw new IllegalStateException("Cannot submit empty order");
        }
        applyEvent(new OrderSubmitted(orderId, Instant.now()));
    }

    public void pay(String paymentId) {
        if (!state.isSubmitted()) {
            throw new IllegalStateException("Order must be submitted first");
        }
        applyEvent(new OrderPaid(orderId, paymentId, Instant.now()));
    }

    private void applyEvent(OrderEvent event) {
        events.add(event);
        state.apply(event);
    }

    public List<OrderEvent> getUncommittedEvents() {
        return new ArrayList<>(events);
    }

    public static OrderAggregate restoreFromEvents(List<OrderEvent> historicalEvents) {
        OrderAggregate aggregate = new OrderAggregate("temp", "temp");
        aggregate.events.clear();
        for (OrderEvent event : historicalEvents) {
            aggregate.state.apply(event);
            aggregate.events.add(event);
        }
        return aggregate;
    }
}

public abstract class OrderEvent {
    private final String orderId;
    private final Instant timestamp;

    protected OrderEvent(String orderId, Instant timestamp) {
        this.orderId = orderId;
        this.timestamp = timestamp;
    }

    public String getOrderId() { return orderId; }
    public Instant getTimestamp() { return timestamp; }
}

record OrderCreated(String orderId, String customerId, Instant timestamp) extends OrderEvent {
    public OrderCreated(String orderId, String customerId, Instant timestamp) {
        super(orderId, timestamp);
    }
}

record ItemAdded(String orderId, String productId, String productName, int quantity, double price, Instant timestamp) extends OrderEvent {
    public ItemAdded(String orderId, String productId, String productName, int quantity, double price, Instant timestamp) {
        super(orderId, timestamp);
    }
}

record OrderSubmitted(String orderId, Instant timestamp) extends OrderEvent {
    public OrderSubmitted(String orderId, Instant timestamp) {
        super(orderId, timestamp);
    }
}

record OrderPaid(String orderId, String paymentId, Instant timestamp) extends OrderEvent {
    public OrderPaid(String orderId, String paymentId, Instant timestamp) {
        super(orderId, timestamp);
    }
}

package com.example.microservice;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.cloud.client.discovery.EnableDiscoveryClient;
import org.springframework.cloud.openfeign.EnableFeignClients;
import org.springframework.context.annotation.Bean;
import org.springframework.web.bind.annotation.*;

@SpringBootApplication
@EnableDiscoveryClient
@EnableFeignClients
public class UserServiceApplication {
    public static void main(String[] args) {
        SpringApplication.run(UserServiceApplication.class, args);
    }

    @Bean
    public RestTemplate restTemplate() {
        return new RestTemplateBuilder()
            .setConnectTimeout(Duration.ofMillis(1000))
            .setReadTimeout(Duration.ofMillis(3000))
            .build();
    }
}

@RestController
@RequestMapping("/api/users")
public class UserController {
    @Autowired
    private UserRepository userRepository;

    @Autowired
    private OrderClient orderClient;

    @Autowired
    private NotificationClient notificationClient;

    @GetMapping("/{id}")
    public ResponseEntity<UserDto> getUser(@PathVariable String id) {
        User user = userRepository.findById(id)
            .orElseThrow(() -> new UserNotFoundException(id));

        UserAggregatedDto dto = new UserAggregatedDto();
        dto.setUser(UserMapper.toDto(user));

        try {
            OrderSummary orders = orderClient.getUserOrders(id);
            dto.setOrderSummary(orders);
        } catch (Exception e) {
            dto.setOrderSummary(null);
        }

        return ResponseEntity.ok(dto);
    }

    @PostMapping
    public ResponseEntity<UserDto> createUser(@RequestBody CreateUserRequest request) {
        User user = UserMapper.toEntity(request);
        User saved = userRepository.save(user);

        notificationClient.sendWelcomeEmail(user.getEmail());

        return ResponseEntity.status(HttpStatus.CREATED).body(UserMapper.toDto(saved));
    }
}

@FeignClient(name = "order-service", fallbackFactory = OrderClientFallbackFactory.class)
public interface OrderClient {
    @GetMapping("/api/orders/user/{userId}")
    OrderSummary getUserOrders(@PathVariable String userId);
}

@Component
public class OrderClientFallbackFactory implements FallbackFactory<OrderClient> {
    @Override
    public OrderClient create(Throwable cause) {
        return new OrderClient() {
            @Override
            public OrderSummary getUserOrders(String userId) {
                return new OrderSummary("ERROR", 0, 0.0);
            }
        };
    }
}

package com.example.repository;

import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.JpaSpecificationExecutor;
import org.springframework.data.repository.NoRepositoryBean;

import java.io.Serializable;
import java.util.Optional;

@NoRepositoryBean
public interface BaseRepository<T, ID extends Serializable>
        extends JpaRepository<T, ID>, JpaSpecificationExecutor<T> {

    Optional<T> findByStatus(EntityStatus status);

    Page<T> findByActiveTrue(Pageable pageable);

    long countByStatus(EntityStatus status);
}

public enum EntityStatus {
    ACTIVE, INACTIVE, ARCHIVED, DELETED
}

@Entity
@Table(name = "products")
public class Product {
    @Id
    @GeneratedValue(strategy = GenerationType.UUID)
    private String id;

    @Column(nullable = false)
    private String name;

    @Column(nullable = false)
    private BigDecimal price;

    @Enumerated(EnumType.STRING)
    private EntityStatus status;

    @Version
    private Long version;

    @CreationTimestamp
    private LocalDateTime createdAt;

    @UpdateTimestamp
    private LocalDateTime updatedAt;
}

@Repository
public interface ProductRepository extends BaseRepository<Product, String> {

    Optional<Product> findByNameAndStatus(String name, EntityStatus status);

    @Query("SELECT p FROM Product p WHERE p.price BETWEEN :min AND :max AND p.status = :status")
    List<Product> findProductsInPriceRange(
        @Param("min") BigDecimal min,
        @Param("max") BigDecimal max,
        @Param("status") EntityStatus status
    );

    @Modifying
    @Query("UPDATE Product p SET p.status = :status WHERE p.id = :id")
    int updateStatus(@Param("id") String id, @Param("status") EntityStatus status);
}

@Service
public class ProductService {
    private final ProductRepository productRepository;

    public Product findById(String id) {
        return productRepository.findById(id)
            .orElseThrow(() -> new NoSuchElementException("Product not found: " + id));
    }

    public Page<Product> searchProducts(ProductSearchCriteria criteria, Pageable pageable) {
        Specification<Product> spec = Specification.where(
            criteria.toSpecification()
        ).and((root, query, cb) -> 
            cb.equal(root.get("status"), EntityStatus.ACTIVE)
        );
        return productRepository.findAll(spec, pageable);
    }
}

package com.example.layered;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;

@SpringBootApplication
public class OrderApplication {
    public static void main(String[] args) {
        SpringApplication.run(OrderApplication.class, args);
    }
}

// Controller Layer
@RestController
@RequestMapping("/api/orders")
public class OrderController {
    private final OrderService orderService;

    public OrderController(OrderService orderService) {
        this.orderService = orderService;
    }

    @PostMapping
    public ResponseEntity<OrderResponse> createOrder(@RequestBody CreateOrderRequest request) {
        Order order = orderService.createOrder(request.toDomain());
        return ResponseEntity.ok(OrderMapper.toResponse(order));
    }

    @GetMapping("/{id}")
    public ResponseEntity<OrderResponse> getOrder(@PathVariable String id) {
        return ResponseEntity.ok(OrderMapper.toResponse(orderService.getOrder(id)));
    }
}

// Service Layer
@Service
@Transactional
public class OrderService {
    private final OrderRepository orderRepository;
    private final InventoryClient inventoryClient;
    private final PaymentService paymentService;

    public Order createOrder(CreateOrderRequest request) {
        Order order = Order.create(request.getCustomerId(), request.getItems());

        // Reserve inventory
        inventoryClient.reserveStock(request.getItems());

        // Process payment
        PaymentResult payment = paymentService.charge(
            request.getCustomerId(),
            order.calculateTotal()
        );

        if (!payment.isSuccess()) {
            inventoryClient.releaseStock(request.getItems());
            throw new PaymentFailedException(payment.getErrorMessage());
        }

        order.markAsPaid(payment.getTransactionId());
        return orderRepository.save(order);
    }

    public Order getOrder(String id) {
        return orderRepository.findById(id)
            .orElseThrow(() -> new OrderNotFoundException(id));
    }
}

// Domain Layer
@Entity
@Table(name = "orders")
public class Order {
    @Id
    private String id;
    private String customerId;
    private List<OrderItem> items;
    private OrderStatus status;
    private BigDecimal totalAmount;

    public static Order create(String customerId, List<OrderItem> items) {
        Order order = new Order();
        order.setId(UUID.randomUUID().toString());
        order.setCustomerId(customerId);
        order.setItems(items);
        order.setStatus(OrderStatus.CREATED);
        order.setTotalAmount(items.stream()
            .map(Item::calculatePrice)
            .reduce(BigDecimal.ZERO, BigDecimal::add));
        return order;
    }

    public void markAsPaid(String transactionId) {
        this.status = OrderStatus.PAID;
    }
}

// Infrastructure Layer
@Repository
public interface OrderRepository extends JpaRepository<Order, String> {
    List<Order> findByCustomerIdOrderByCreatedAtDesc(String customerId);
}

package com.example.resilience;

import io.github.resilience4j.circuitbreaker.CircuitBreaker;
import io.github.resilience4j.circuitbreaker.CircuitBreakerConfig;
import io.github.resilience4j.circuitbreaker.CircuitBreakerRegistry;
import io.github.resilience4j.ratelimiter.RateLimiter;
import io.github.resilience4j.ratelimiter.RateLimiterConfig;
import io.github.resilience4j.ratelimiter.RateLimiterRegistry;
import io.github.resilience4j.retry.Retry;
import io.github.resilience4j.retry.RetryConfig;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import java.time.Duration;
import java.util.Map;

@Configuration
public class CircuitBreakerConfig {

    @Bean
    public CircuitBreakerRegistry circuitBreakerRegistry() {
        CircuitBreakerConfig config = CircuitBreakerConfig.custom()
            .failureRateThreshold(50)
            .waitDurationInOpenState(Duration.ofSeconds(10))
            .slidingWindowType(CircuitBreakerConfig.SlidingWindowType.COUNT_BASED)
            .slidingWindowSize(10)
            .minimumNumberOfCalls(5)
            .permittedNumberOfCallsInHalfOpenState(3)
            .automaticTransitionFromOpenToHalfOpenEnabled(true)
            .build();

        return CircuitBreakerRegistry.of(config);
    }

    @Bean
    public Retry retry() {
        return Retry.of("paymentService", RetryConfig.custom()
            .maxAttempts(3)
            .waitDuration(Duration.ofMillis(500))
            .retryExceptions(Exception.class)
            .ignoreExceptions(IllegalArgumentException.class)
            .build());
    }

    @Bean
    public RateLimiterRegistry rateLimiterRegistry() {
        return RateLimiterRegistry.of(RateLimiterConfig.custom()
            .limitForPeriod(100)
            .limitRefreshPeriod(Duration.ofSeconds(1))
            .timeoutDuration(Duration.ofMillis(100))
            .build());
    }
}

@Service
public class ResilientPaymentService {
    private final CircuitBreaker circuitBreaker;
    private final Retry retry;
    private final RateLimiter rateLimiter;

    public PaymentResult processPayment(PaymentRequest request) {
        // Rate limiting
        if (!rateLimiter.tryAcquirePermission()) {
            return PaymentResult.rateLimited();
        }

        // Retry with circuit breaker
        Supplier<PaymentResult> decoratedSupplier = Retry.decorateSupplier(
            retry,
            () -> circuitBreaker.executeSupplier(() -> 
                actualPaymentProcessor.process(request)
            )
        );

        return decoratedSupplier.get();
    }
}

package com.example.eventdriven;

import org.apache.kafka.clients.producer.KafkaProducer;
import org.apache.kafka.clients.producer.ProducerRecord;
import org.apache.kafka.clients.producer.RecordMetadata;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.support.SendResult;
import org.springframework.stereotype.Service;

import java.util.concurrent.CompletableFuture;

@Service
public class OrderEventPublisher {
    private static final Logger log = LoggerFactory.getLogger(OrderEventPublisher.class);

    private final KafkaTemplate<String, OrderEvent> kafkaTemplate;

    public OrderEventPublisher(KafkaTemplate<String, OrderEvent> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public CompletableFuture<Void> publishOrderEvent(OrderEvent event) {
        log.info("Publishing order event: {} for order {}", event.getEventType(), event.getOrderId());

        return kafkaTemplate.send("order-events", event.getOrderId(), event)
            .addListener((SendResult<String, OrderEvent> result) -> {
                RecordMetadata metadata = result.getRecordMetadata();
                log.info("Event sent successfully: topic={}, partition={}, offset={}",
                    metadata.topic(), metadata.partition(), metadata.offset());
            })
            .exceptionally(ex -> {
                log.error("Failed to send order event", ex);
                throw new EventPublishingException("Failed to publish event", ex);
            });
    }

    public void publishOrderCreated(OrderCreatedEvent event) {
        publishOrderEvent(event);
    }

    public void publishOrderPaid(OrderPaidEvent event) {
        publishOrderEvent(event);
    }

    public void publishOrderShipped(OrderShippedEvent event) {
        publishOrderEvent(event);
    }
}

@KafkaListener(topics = "inventory-events", groupId = "inventory-service")
@Service
public class InventoryEventConsumer {
    private final InventoryService inventoryService;

    @KafkaHandler
    public void handleOrderPaid(OrderPaidEvent event) {
        log.info("Processing order paid event: {}", event.getOrderId());
        inventoryService.decreaseStock(event.getItems());
    }

    @KafkaHandler
    public void handleOrderCancelled(OrderCancelledEvent event) {
        log.info("Restocking for cancelled order: {}", event.getOrderId());
        inventoryService.increaseStock(event.getItems());
    }
}

