package com.example.gateway;

import org.springframework.cloud.gateway.route.RouteLocator;
import org.springframework.cloud.gateway.route.builder.RouteLocatorBuilder;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.HttpStatus;
import org.springframework.web.reactive.handler.SimpleMappingExceptionResolver;
import org.springframework.web.server.ServerWebExchange;
import reactor.core.publisher.Mono;

import java.util.Map;

@Configuration
public class GatewayConfig {

    @Bean
    public RouteLocator customRoutes(RouteLocatorBuilder builder) {
        return builder.routes()
            .route("user-service", r -> r
                .path("/api/users/**")
                .filters(f -> f
                    .stripPrefix(2)
                    .addResponseHeader("X-Gateway", "spring-cloud")
                    .circuitBreaker(config -> config
                        .setName("userServiceCircuitBreaker")
                        .setFallbackUri("forward:/fallback/users"))
                    .retry(retry -> retry
                        .setRetries(3)
                        .setStatuses(HttpStatus.BAD_GATEWAY))
                    .requestRateLimiter(config -> config
                        .setRateLimiter(redisRateLimiter())
                        .setKeyResolver(ipKeyResolver()))
                )
                .uri("lb://user-service"))
            .route("order-service", r -> r
                .path("/api/orders/**")
                .filters(f -> f
                    .stripPrefix(2)
                    .circuitBreaker(config -> config
                        .setName("orderServiceCircuitBreaker")
                        .setFallbackUri("forward:/fallback/orders"))
                )
                .uri("lb://order-service"))
            .route("product-service", r -> r
                .path("/api/products/**")
                .filters(f -> f
                    .stripPrefix(2)
                    .requestHeader("X-Request-Id", "(.*)")
                        .addRequestHeader("X-Gateway-RequestId", "$1"))
                )
                .uri("lb://product-service"))
            .build();
    }

    @Bean
    public GlobalFilter authenticationFilter() {
        return (exchange, chain) -> {
            String token = exchange.getRequest().getHeaders()
                .getFirst("Authorization");

            if (token == null || !token.startsWith("Bearer ")) {
                exchange.getResponse().setStatusCode(HttpStatus.UNAUTHORIZED);
                return exchange.getResponse().writeWith(
                    Mono.just(exchange.getResponse()
                        .bufferFactory()
                        .wrap("{\"error\":\"Unauthorized\"}".getBytes())));
            }

            String userId = JwtValidator.validate(token.substring(7));
            exchange.getRequest().mutate()
                .header("X-User-Id", userId)
                .build();

            return chain.filter(exchange);
        };
    }

    @Bean
    public KeyResolver ipKeyResolver() {
        return exchange -> Mono.just(
            exchange.getRequest().getRemoteAddress() != null ?
            exchange.getRequest().getRemoteAddress().getAddress().getHostAddress() : "anonymous");
    }
}
